const w = $input.first() ? $input.first().json : null;
if (!w || !w.starts_at) { return []; }
const start = new Date(w.starts_at).getTime();
const mins = (start - Date.now()) / 60000;
const link = w.join_url || '';
const hasLink = /^https?:/i.test(link);
const ld = hasLink ? link : '(link coming soon)';
const button = hasLink
  ? `<p style='margin:26px 0;'><a href='${link}' style='display:inline-block;background:#4456BE;color:#ffffff;text-decoration:none;padding:13px 26px;border-radius:6px;font-weight:600;'>Join the workshop</a></p>`
  : `<p style='margin:22px 0;color:#888888;'>Your join link will arrive here right before we start.</p>`;
const wrap = (intro) => `<div style='font-family:-apple-system,Segoe UI,Roboto,Arial,sans-serif;font-size:16px;line-height:1.6;color:#1a1a1a;max-width:520px;margin:0 auto;'><p>Hi {NAME},</p><p>${intro}</p>${button}<p style='color:#555555;margin-top:24px;'>See you there,<br><strong>Maria</strong></p></div>`;
let step=null, message=null, emailSubject=null, emailText=null, emailHtml=null;
if (mins <= 1440 && mins > 180) {
  step='day_before';
  message=`⏰ Reminder: "${w.title}" is tomorrow at {TIME}.\nSave the link: ${ld}`;
  emailSubject=`Tomorrow: ${w.title}`;
  emailText=`Hi {NAME},\n\nQuick reminder — "${w.title}" is tomorrow at {TIME}.\n\nJoin: ${ld}\n\nSee you there,\nMaria`;
  emailHtml=wrap(`Quick reminder — the workshop <strong>&ldquo;${w.title}&rdquo;</strong> is <strong>tomorrow at {TIME}</strong>.`);
} else if (mins <= 180 && mins > 60) {
  step='soon_3h';
  message=`📌 Today! "${w.title}" goes live at {TIME}.\nJoin: ${ld}`;
  emailSubject=`Today at {TIME}: ${w.title}`;
  emailText=`Hi {NAME},\n\nWe go live today at {TIME}.\n\nJoin: ${ld}\n\nSee you soon,\nMaria`;
  emailHtml=wrap(`We go live <strong>today at {TIME}</strong>.`);
} else if (mins <= 60 && mins > 15) {
  step='hour_before';
  message=`🔔 We go live in about an hour, at {TIME}.\nJoin: ${ld}`;
  emailSubject=`Starting in about an hour`;
  emailText=`Hi {NAME},\n\nWe go live in about an hour, at {TIME}.\n\nJoin: ${ld}\n\nMaria`;
  emailHtml=wrap(`We go live in <strong>about an hour</strong>, at {TIME}.`);
} else if (mins <= 15 && mins > 0) {
  step='fifteen_min';
  message=`🚀 Starting in ~15 minutes! Grab a pen.\nJoin now: ${ld}`;
  emailSubject=`We start in ~15 minutes`;
  emailText=`Hi {NAME},\n\nWe go live in about 15 minutes. Grab a pen.\n\nJoin now: ${ld}\n\nMaria`;
  emailHtml=wrap(`We go live in <strong>about 15 minutes</strong>. Grab a pen.`);
} else if (mins <= 0 && mins > -20) {
  step='live';
  message=`🔴 We're LIVE now — come in!\n${ld}`;
  emailSubject=`We're live now`;
  emailText=`Hi {NAME},\n\nWe just went live — come on in:\n${ld}\n\nMaria`;
  emailHtml=wrap(`We&rsquo;re <strong>live now</strong> — come on in.`);
}
if (!step) { return []; }
return [{ json: { slug:w.slug, title:w.title, starts_at:w.starts_at, join_url:link, step, message, emailSubject, emailText, emailHtml } }];
